mapper.select:
SELECT c.*
FROM ts_story_chapter c
INNER JOIN ts_story_info s ON s.id = c.story_id
WHERE s.user_id = #{query.userId}
  AND s.is_deleted = 0
  AND c.story_id = #{query.storyId}

    AND (
        c.chapter_title LIKE CONCAT('%', #{query.keyword}, '%')
        OR c.chapter_desc LIKE CONCAT('%', #{query.keyword}, '%')
    )



        AND c.status = #{query.status}


        AND (c.status IS NULL OR c.status != 0)


ORDER BY c.sort_no ASC, c.chapter_no ASC, c.id ASC

SELECT COUNT(1)
FROM ts_story_chapter
WHERE story_id = #{storyId}
  AND chapter_no = #{chapterNo}
  AND (status IS NULL OR status != 0)

    AND id != #{excludeId}

SELECT chapter_id AS chapterId, role_id AS roleId FROM ts_story_chapter_forbidden_role WHERE chapter_id IN
#{chapterId}
ORDER BY chapter_id ASC, id ASC
